import{_ as i,o as t,c as a,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Power Quality Monitoring","description":"","frontmatter":{},"headers":[],"relativePath":"en/power-quality/monitoring.md","filePath":"en/power-quality/monitoring.md"}'),o={name:"en/power-quality/monitoring.md"};function n(s,e,l,c,p,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="power-quality-monitoring" tabindex="-1">Power Quality Monitoring <a class="header-anchor" href="#power-quality-monitoring" aria-label="Permalink to &quot;Power Quality Monitoring&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Power quality monitoring is the process of measuring and analyzing electrical parameters to detect disturbances and assess system performance.</p><p>It provides visibility into how voltage, current, and waveform conditions behave over time.</p><p>Monitoring is essential for identifying issues such as sags, swells, harmonics, and transients.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of power quality monitoring is to:</p><ul><li>Detect and record power quality disturbances</li><li>Identify the source of electrical issues</li><li>Support troubleshooting and corrective actions</li><li>Verify system performance and compliance</li><li>Improve reliability and reduce downtime</li></ul><p>Without monitoring, many power quality problems remain unnoticed until failures occur.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Monitoring systems use measurement devices installed at key points in the electrical system.</p><p>These devices continuously record parameters such as:</p><ul><li>Voltage and current levels</li><li>Frequency</li><li>Harmonic distortion</li><li>Event based disturbances like sags or surges</li></ul><p>Data is stored and analyzed to identify patterns, trends, and abnormal events.</p><p>Advanced systems can trigger alarms or generate reports when thresholds are exceeded.</p><p>Monitoring can be:</p><ul><li>Continuous for critical systems</li><li>Temporary for troubleshooting specific issues</li></ul><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Power quality monitoring is used in:</p><ul><li>Industrial facilities with sensitive equipment</li><li>Systems experiencing frequent disturbances</li><li>Critical infrastructure requiring high reliability</li><li>Facilities with high levels of nonlinear loads</li><li>Energy management and optimization programs</li></ul><p>It is valuable both during design validation and ongoing operation.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><p><strong>Measurement location</strong><br> Monitoring points should be selected to capture relevant data</p></li><li><p><strong>Parameters tracked</strong><br> Must align with expected issues such as harmonics or voltage events</p></li><li><p><strong>Data resolution</strong><br> High speed events require appropriate sampling rates</p></li><li><p><strong>Data analysis</strong><br> Tools and expertise are needed to interpret results</p></li><li><p><strong>Integration</strong><br> Monitoring systems may connect to SCADA or data platforms</p></li><li><p><strong>Cost and complexity</strong><br> Must be balanced with the importance of the system</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Installing monitors at main and critical loads provides better visibility</li><li>Temporary monitoring is useful for diagnosing intermittent problems</li><li>Long term data helps identify recurring patterns and root causes</li><li>Poor data interpretation can lead to incorrect conclusions</li><li>Monitoring should be combined with corrective actions for real improvement</li></ul>',25)])])}const h=i(o,[["render",n]]);export{m as __pageData,h as default};
